            done();
        }).catch(done);

        deferred.resolve(testValue);
    });

    it('test q.defer - reject with error', function(done) {
        let deferred = q.defer();
        let testError = new Error('test error');

        deferred.promise.then(function() {
            done(new Error('promise should not resolve'));
        }).catch(function(error) {
            assert.equal(error, testError, 'promise should reject with the correct error');
            done();
        });

        deferred.reject(testError);
    });

    it('test q.defer - multiple resolves only use first', function(done) {
        let deferred = q.defer();
        let firstValue = 'first';
        let secondValue = 'second';

        deferred.promise.then(function(result) {
            assert.equal(result, firstValue, 'promise should resolve with first value only');
            done();
        }).catch(done);

        deferred.resolve(firstValue);
        deferred.resolve(secondValue); // This should be ignored
    });

    it('test q.defer - chaining with then', function(done) {
