        });

        deferred.notify('progress1');
        deferred.resolve('resolved');
        deferred.notify('progress2'); // This should be ignored

        promise.then(function(result) {
            assert.equal(result, 'resolved');
            assert.equal(progressCount, 1);
            done();
        }).catch(done);
    });

