                done();
            });
    });

    it('test q.done with rejected promise', function(done) {
        let errorCaught = false;

        // Temporarily override process.nextTick to catch the error
        let originalNextTick = process.nextTick;
        process.nextTick = function(callback) {
            try {
                callback();
            } catch (error) {
                errorCaught = true;
                assert.equal(error.message, 'test error');
                process.nextTick = originalNextTick;
                done();
            }
        };

        q.reject(new Error('test error'))
            .done();
    });

    it('test q.done with promise chain', function(done) {
        q.resolve(5)
            .then(function(value) {
                return value * 2;
            })
            .then(function(value) {
                return value + 3;
            })
            .done(function(finalValue) {
                assert.equal(finalValue, 13);
                done();
            });
    });

    it('test q.done without callback (just terminates chain)', function(done) {
        q.resolve('completed')
            .then(function(value) {
                assert.equal(value, 'completed');
                return value;
            })
            .done();

        // Give it a moment to complete
        setTimeout(done, 10);
    });

    it('test q.done with progress callback', function(done) {
        let deferred = q.defer();
        let progressValues = [];

        deferred.promise.done(
            function(value) {
                assert.equal(value, 'final');
                assert.deepEqual(progressValues, [25, 50, 75]);
                done();
            },
            null,
            function(progress) {
                progressValues.push(progress);
            }
        );

        deferred.notify(25);
        deferred.notify(50);
        deferred.notify(75);
        deferred.resolve('final');
    });

    it('test q.done with all three callbacks', function(done) {
        let deferred = q.defer();
        let progressReceived = false;

        deferred.promise.done(
            function(value) {
                assert.equal(value, 'success');
                assert.equal(progressReceived, true);
                done();
            },
            function(error) {
                done(error);
            },
            function(progress) {
                progressReceived = true;
                assert.equal(progress, 'working...');
            }
        );

        deferred.notify('working...');
        deferred.resolve('success');
    });

    it('test q.done error thrown in callback gets propagated', function(done) {
        let originalNextTick = process.nextTick;
        process.nextTick = function(callback) {
            try {
                callback();
            } catch (error) {
                assert.equal(error.message, 'callback error');
                process.nextTick = originalNextTick;
                done();
            }
        };

        q.resolve('value')
            .done(function(value) {
                throw new Error('callback error');
            });
    });
});
```

This test suite covers:

1. **Basic fulfilled promise**: Tests that `done()` receives the resolved value
2. **Rejected promise**: Tests that unhandled rejections are thrown globally
3. **Promise chain**: Tests `done()` at the end of a promise chain
4. **No callback**: Tests `done()` without any callbacks (just terminates the chain)
5. **Progress callback**: Tests the progress parameter functionality
6. **All three callbacks**: Tests fulfilled, rejected, and progress callbacks together
7. **Error propagation**: Tests that errors thrown in the done callback are propagated globally

The tests handle the asynchronous nature of promises and the fact that `done()` throws unhandled errors globally by temporarily overriding `process.nextTick` to catch those errors in a controlled way.

